Set-Location "C:\burak_otokurtarici\burak-oto"
New-Item -ItemType Directory -Force -Path "css","js","php","images" | Out-Null
if (Test-Path "php\api.php") { Remove-Item "php\api.php" -Force }
Write-Host "Dosyalar yaziliyor..." -ForegroundColor Cyan
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path (Get-Location) "index.html"), $b)
Write-Host "OK: index.html" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path (Get-Location) "css\style.css"), $b)
