$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path (Get-Location) "js\main.js"), $b)
Write-Host "OK: js\main.js" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path (Get-Location) "php\contact.php"), $b)
Write-Host "OK: php\contact.php" -ForegroundColor Green
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes((Join-Path (Get-Location) ".htaccess"), $b)
